import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

class Solution {
    public List<String> letterCombinationsOfAPhoneNumber(String data) {
        List<String> result = new ArrayList<>();
        if (data == null || data.length() == 0) {
            return result;
        }

        Map<Character, String> phoneMap = new HashMap<>();
        phoneMap.put('2', "abc");
        phoneMap.put('3', "def");
        phoneMap.put('4', "ghi");
        phoneMap.put('5', "jkl");
        phoneMap.put('6', "mno");
        phoneMap.put('7', "pqrs");
        phoneMap.put('8', "tuv");
        phoneMap.put('9', "wxyz");

        backtrack(result, new StringBuilder(), data, phoneMap, 0);
        return result;
    }

    private void backtrack(List<String> result, StringBuilder combination, String data, Map<Character, String> phoneMap, int index) {
        if (index == data.length()) {
            result.add(combination.toString());
            return;
        }

        char digit = data.charAt(index);
        String letters = phoneMap.get(digit);

        for (char letter : letters.toCharArray()) {
            combination.append(letter);
            backtrack(result, combination, data, phoneMap, index + 1);
            combination.deleteCharAt(combination.length() - 1);
        }
    }
}

