        if (data.empty()) return result;

        vector<string> mapping = {"", "", "abc", "def", "ghi", "jkl", "mno", "pqrs", "tuv", "wxyz"};
        string current;
        backtrack(result, current, data, mapping, 0);
        return result;
    }

private:
    void backtrack(vector<string>& result, string& current, string& data, vector<string>& mapping, int index) {
        if (index == data.size()) {
            result.push_back(current);
            return;
        }

        int digit = data[index] - '0';
        for (char letter : mapping[digit]) {
            current.push_back(letter);
            backtrack(result, current, data, mapping, index + 1);
            current.pop_back();
        }
    }
